# Worked focus: http-py-request-components — Construct a request with an intentional method, target, fields, body, context, and caller-owned policy. Demonstrate the result through Python 3.14 urllib, http.client, ssl, typed protocols, and fixture transports.
def worked_http_py_requests_methods_2(method: str, replayable: bool) -> dict[str, object]:
    assert isinstance(method, str) and isinstance(replayable, bool)
    normalized = method.upper()
    safe = normalized in {"GET", "HEAD", "OPTIONS"}
    idempotent = safe or normalized in {"PUT", "DELETE"}
    return {"method": normalized, "safe": safe, "retryable": idempotent and replayable}

